#include <iostream>
#include <stack>

class MyQueue {
public:
    MyQueue() {}

    void push(int x) {
        std::stack<int> frontStack;
        std::stack<int> rearStack;

        frontStack.push(x);
    }

    int pop() {
        if (rearStack.empty()) {
            std::cout << "Queue is empty";
            return -1;
        }

        int topFront = frontStack.top();
        frontStack.pop();
        rearStack.push(topFront);

        return topFront;
    }

    int peek() {
        if (rearStack.empty()) {
            std::cout << "Queue is empty";
            return -1;
        }

        int topRear = rearStack.top();
        return topRear;
    }

    bool empty() {
        return rearStack.empty();
    }
};
```

